	const badgeNameWithLength = {
		properties: {
			attribute: 'name',
			initialOperatorOpened: true,
			initialValueOpened: false,
			label: 'Name',
			operator: {},
			operators: [],
			type: 'text',
			placeholder: 'Enter a dataset name',
		},
		metadata: {
			isAvailableForQuickSearch: true,
			isAvailableForFacetList: true,
			badgePerFacet: 'N',
			entitiesPerBadge: '1',
			operators: [
				'containsIgnoreCase',
				'notContainsIgnoreCase',
				'equals',
				'notEquals',
				'match a regexp',
			],
			'data-feature': 'faceted-badge-name',
			minLength: 5,
		},
	};
	return (
		<FacetedSearch.Faceted id="my-faceted-search">
			<p>
				Quick search will trigger after a minimum input length that can be customized based on badge
				definition
			</p>
			<br />
			<FacetedSearch.BasicSearch
				badgesDefinitions={[badgeNameWithLength]}
				callbacks={callbacks}
				onSubmit={onSubmit}
			/>
		</FacetedSearch.Faceted>
	);
};

const WithQuickSearchAsynchronousSuggestions = () => {
	const [searching, setSearching] = useState(false);
	const [items, setItems] = useState([]);
	const [value, setValue] = useState('');
	const onChange = (_, { value }) => {
		setValue(value);
		setSearching(true);
		setTimeout(() => {
			setItems([
				{
					title: 'Search in...',
					suggestions: ['in Name', 'in Email', 'in Position'].map(column => value + ' ' + column),
				},
			]);
			setSearching(false);
		}, 1000);
	};

	return (
		<FacetedSearch.Faceted id="my-faceted-search">
			<FacetedSearch.BasicSearch
				badgesDefinitions={badgesDefinitions}
				callbacks={callbacks}
				onSubmit={onSubmit}
				quickSearchInputProps={{ value }}
				quickSearchTypeaheadProps={{ searching, items, onChange, debounceTimeout: 800 }}
			/>
		</FacetedSearch.Faceted>
	);
};

